(() => {
  class VideoURLCollector {
    constructor(options = {}) {
      const container = options.scrollContainer || document.getElementById('pageScroll');
      if (!container) throw new Error('Scroll container #pageScroll not found.');
      this.scrollContainer = container;

      this.maxVideos = options.maxVideos ?? 100;        // target
      this.batchWaitTime = options.batchWaitTime ?? 5000; // legacy, still used between attempts
      this.scrollStepRatio = options.scrollStepRatio ?? 0.9; // how far towards bottom per step
      this.lazyPollMs = options.lazyPollMs ?? 2500;     // how long to poll after a scroll for new URLs
      this.lazyPollInterval = options.lazyPollInterval ?? 300; // poll cadence
      this.noProgressLimit = options.noProgressLimit ?? 6; // how many consecutive no-progress steps before stopping

      this.videoUrls = new Set();
      this.isRunning = false;
      this.attempt = 0;
    }

    delay(ms) { return new Promise(res => setTimeout(res, ms)); }

    static cssEscape(str) {
      if (window.CSS && typeof window.CSS.escape === 'function') return window.CSS.escape(str);
      return String(str).replace(/[^a-zA-Z0-9_\-]/g, s => '\\' + s.charCodeAt(0).toString(16) + ' ');
    }

    normalizeUrl(url) {
      if (!url) return null;
      try { const u = new URL(url, location.href); u.hash = ''; return u.href; } catch { return null; }
    }

    getVideoUrls() {
      const urls = new Set();
      document.querySelectorAll('video[src]').forEach(v => { const u = this.normalizeUrl(v.getAttribute('src')); if (u && u.endsWith('.mp4')) urls.add(u); });
      document.querySelectorAll('source[src]').forEach(s => { const u = this.normalizeUrl(s.getAttribute('src')); if (u && u.endsWith('.mp4')) urls.add(u); });
      document.querySelectorAll("a[href*='.mp4']").forEach(a => { const u = this.normalizeUrl(a.getAttribute('href')); if (u && u.endsWith('.mp4')) urls.add(u); });
      document.querySelectorAll('[data-src],[data-url]').forEach(el => { const cand = el.getAttribute('data-src') || el.getAttribute('data-url'); const u = this.normalizeUrl(cand); if (u && u.endsWith('.mp4')) urls.add(u); });
      return Array.from(urls);
    }

    ensureHighlightStyles() {
      if (document.getElementById('__video_pick_styles')) return;
      const style = document.createElement('style');
      style.id = '__video_pick_styles';
      style.textContent = `.video-picked{border:3px dotted #00ff3b!important;border-radius:12px;box-shadow:0 0 0 2px rgba(16,185,129,.15);transition:all .2s ease;background:rgba(16,185,129,.05)!important}.batch-highlight{border:2px solid #06f!important;box-shadow:0 0 8px rgba(0,102,255,.3)}`;
      document.head.appendChild(style);
    }

    highlightBatchElements(newUrls) {
      this.ensureHighlightStyles();
      newUrls.forEach(url => {
        try {
          const esc = VideoURLCollector.cssEscape(url);
          const nodes = [
            ...document.querySelectorAll(`video[src="${esc}"]`),
            ...document.querySelectorAll(`source[src="${esc}"]`)
          ];
          nodes.forEach(node => {
            const card = node.closest('div[draggable="true"]') || node.closest('a') || node;
            if (card) {
              card.classList.add('video-picked','batch-highlight');
              setTimeout(() => card.classList.remove('batch-highlight'), 2000);
            }
          });
        } catch {}
      });
    }

    saveUrls(urls) {
      const newlyAdded = [];
      urls.forEach(u => { if (u && !this.videoUrls.has(u)) { this.videoUrls.add(u); newlyAdded.push(u); }});
      if (newlyAdded.length) {
        console.log(`+ added ${newlyAdded.length} (total ${this.videoUrls.size}/${this.maxVideos})`);
      }
      return newlyAdded;
    }

    // Core: scroll near bottom, then poll briefly for new items
    async scrollAndHarvestOnce() {
      const c = this.scrollContainer;
      const beforeTop = c.scrollTop;
      const beforeHeight = c.scrollHeight;

      // Scroll towards bottom
      const step = Math.floor(c.clientHeight * this.scrollStepRatio);
      c.scrollTop = Math.min(beforeTop + step, c.scrollHeight);
      console.log(`[Attempt ${this.attempt}] Scrolled: top ${beforeTop} -> ${c.scrollTop} (h=${beforeHeight})`);

      // Poll for lazy-load
      const start = Date.now();
      let grew = false;
      while (Date.now() - start < this.lazyPollMs) {
        automaResetTimeout();
        const prev = this.videoUrls.size;
        const newUrls = this.saveUrls(this.getVideoUrls());
        if (newUrls.length) { this.highlightBatchElements(newUrls); grew = true; break; }
        await this.delay(this.lazyPollInterval);
      }

      // Detect end-of-list if height/top no longer change meaningfully
      const ended = !grew && c.scrollTop >= (c.scrollHeight - c.clientHeight - 2);
      return { grew, ended };
    }

    async main() {
      if (this.isRunning) return this.getCollectedUrls();
      this.isRunning = true; this.attempt = 0;
      console.log(`🚀 Collecting up to ${this.maxVideos} videos...`);

      try {
        automaResetTimeout();
        // Seed from current viewport
        const seed = this.saveUrls(this.getVideoUrls());
        if (seed.length) this.highlightBatchElements(seed);

        let noProgress = 0;
        while (this.videoUrls.size < this.maxVideos && noProgress < this.noProgressLimit) {
          this.attempt++;
          automaResetTimeout();

          const { grew, ended } = await this.scrollAndHarvestOnce();
          if (grew) {
            noProgress = 0;
            console.log(`✓ Progress: ${this.videoUrls.size}/${this.maxVideos}`);
          } else {
            noProgress++;
            console.log(`… No progress (${noProgress}/${this.noProgressLimit})`);
          }

          if (ended) {
            console.log('Reached end of list / container height.');
            break;
          }
        }

        const result = Array.from(this.videoUrls).slice(0, this.maxVideos);
        window.__collectedMp4Urls__ = result;
        console.log(`✅ Done. Collected ${result.length} unique .mp4 URLs in ${this.attempt} attempts.`);
        if (result.length < this.maxVideos) console.log('💡 Fewer items available than target; stopping gracefully.');
        return result;
      } catch (e) {
        console.error('❌ Collection error:', e);
        return Array.from(this.videoUrls);
      } finally { this.isRunning = false; }
    }

    getCollectedUrls() { return Array.from(this.videoUrls); }
  }

  const VideoCollectorUtils = {
    async collectVideos(maxVideos = 100, options = {}) {
      const collector = new VideoURLCollector({ maxVideos, ...options });
      return await collector.main();
    },
    createCollector(options = {}) { return new VideoURLCollector(options); }
  };

  window.VideoURLCollector = VideoURLCollector;
  window.VideoCollectorUtils = VideoCollectorUtils;
})();

function transformUrlsToObjects(urls) {
  return urls.map(videoUrl => {
    const match = videoUrl.match(/\/video\/([^/]+)\//);
    const videoName = match ? match[1] : null;
    const pageUrl = videoName ? `https://www.midjourney.com/jobs/${videoName}?index=0` : null;
    return { videoUrl, pageUrl, videoName, downloaded: false };
  });
}

(() => {
  let __done = false; const nextOnce = () => { if (!__done) { __done = true; automaNextBlock(); } };
  (async function runVideoCollection() {
    try {
      automaResetTimeout();
      const urls = await VideoCollectorUtils.collectVideos(500, {
        scrollStepRatio: 0.92,
        lazyPollMs: 3000,
        lazyPollInterval: 300,
        noProgressLimit: 8
      });
      const videos = transformUrlsToObjects(urls);
      automaSetVariable('videos', videos);
      console.log('✅ videos set:', videos.length);
      console.log('✅ videos set raw array:', videos);
      nextOnce();
    } catch (err) {
      console.error('❌ Error in runVideoCollection:', err);
      automaSetVariable('videos', []);
      nextOnce();
    }
  })();
})();
